finished ='';
}
var score = String(java.getString('$.score'));
if(score == '0.0' || score == '') {
score = ''
} else {
score = parseFloat(score).toFixed(2) + '分';
}
var source = String(java.getString('$.source'));
if (source && source === '1') {
source = '原创';
} else {
source = '';
}
var pornRateDesc = java.getString('$.pornRateDesc');
if (baseUrl.match(/novel/)) {
if (pornRateDesc == '') {
pornRateDesc = '非肉文';
} else {
pornRateDesc = String(pornRateDesc).replace(/.*\((.*?)\)/,'$1');
}
} else {
pornRateDesc = '';
}
var categories = java.getString('$.categories');
var tags = java.getString('$.tags');
var viewCountFormat = Formatting(java.getString('$.viewCountFormat'));
