var collectCountFormat = Formatting(java.getString('$.collectCountFormat'));
collectCountFormat = baseUrl.match(/audio|comic|video/)?'收藏:'+collectCountFormat:'';
[word, score, finished, source, pornRateDesc, viewCountFormat, collectCountFormat, categories, tags]

