    /* 内容区 */
    .content-container {
      padding: 16px;
    }

    /* 状态提示 */
    .status-alert {
      background: var(--card-bg);
      border-radius: 16px;
      box-shadow: var(--shadow);
      margin-bottom: 16px;
      overflow: hidden;
      border: 1px solid rgba(120, 130, 240, 0.1);
      padding: 12px 16px;
      display: flex;
      align-items: center;
      justify-content: center;
      gap: 10px;
      font-weight: 500;
      font-size: 14px;
      animation: slideIn 0.5s ease 0.3s backwards;
    }

    .status-alert i {
      font-size: 20px;
    }

    .status-alert.update-available {
      background: linear-gradient(135deg, #ffeaa7 0%, #fdcb6e 100%);
      color: #d63031;
      box-shadow: 0 4px 15px rgba(253, 203, 110, 0.4);
    }

    .status-alert.up-to-date {
      background: linear-gradient(135deg, #55efc4 0%, #00b894 100%);
      color: white;
      box-shadow: 0 4px 15px rgba(0, 184, 148, 0.4);
    }

    /* 更新容器 */
    .update-container {
      background: var(--card-bg);
      border-radius: 16px;
      box-shadow: var(--shadow);
      margin-bottom: 16px;
      overflow: hidden;
      border: 1px solid rgba(120, 130, 240, 0.1);
      animation: slideIn 0.5s ease 0.4s backwards;
    }

    .update-header {
      background: var(--light-bg);
      padding: 12px 16px;
      display: flex;
      justify-content: space-between;
      align-items: center;
      border-bottom: 1px solid var(--border-color);
    }

    .update-header h2 {
      font-size: 1rem;
      font-weight: 600;
      color: var(--text-main);
      display: flex;
      align-items: center;
      gap: 8px;
    }

    .update-header h2 i {
      color: #4e6ef2;
    }

    .update-tag {
      background: rgba(78, 110, 242, 0.1);
      color: #4e6ef2;
      padding: 4px 8px;
      border-radius: 8px;
      font-size: 0.75rem;
      font-weight: 600;
    }

    .update-content {
      padding: 16px;
    }

    .update-date {
      font-weight: 600;
      color: #4e6ef2;
      margin-bottom: 12px;
      display: flex;
      align-items: center;
      gap: 6px;
      padding: 8px 0;
      border-bottom: 1px dashed #e0e0e0;
    }

    .update-text {
      margin: 8px 0;
      position: relative;
      padding-left: 16px;
      line-height: 1.5;
      color: var(--text-main);
      font-size: 0.95rem;
      white-space: pre-wrap;
      word-break: break-word;
    }

    .update-text::before {
      content: '•';
