            href = a.select("a").attr("href");

            // 根据VIP状态选择符号
            if (vip) {
                symbol = "💎";
            } else {
                symbol = "💮";
            }

            // 计算填充空格数量，使符号与章节名称对齐
            padding = "  ".repeat(Math.max(0, text.length - symbol.length));

            // 组合符号和章节名称
            formattedText = symbol + "〖" + text + padding + "〗" + symbol;

            // 添加到列表
            list.push({   
                text: formattedText,
                href: href,
                info: info,
                vip: vip
            });
        });
    }
}
